import random


def _derangement(n):
    if n == 0:
        return 1
    if n == 1:
        return 0
    a, b = 1, 0
    for k in range(2, n + 1):
        a, b = b, (k - 1) * (a + b)
    return b


def generate(seed):
    rng = random.Random(seed)
    n = rng.randint(7, 11)
    fixed = rng.randint(1, 3)
    remaining = n - fixed

    # Calculate the derangement for the remaining people
    derangement = _derangement(remaining)

